SELECT * FROM adoption


        AND animal_id = #{queryDto.animalId}


        AND user_id = #{queryDto.userId}


        AND status = #{queryDto.status}


        AND animal_name LIKE concat('%', #{queryDto.animalName}, '%')


        AND user_name LIKE concat('%', #{queryDto.userName}, '%')


ORDER BY create_time DESC

    LIMIT #{queryDto.current}, #{queryDto.size}

SELECT COUNT(*) FROM adoption


        AND animal_id = #{queryDto.animalId}


        AND user_id = #{queryDto.userId}


        AND status = #{queryDto.status}


        AND animal_name LIKE concat('%', #{queryDto.animalName}, '%')


        AND user_name LIKE concat('%', #{queryDto.userName}, '%')

SELECT * FROM adoption
WHERE user_id = #{userId}
ORDER BY create_time DESC

SELECT * FROM adoption
WHERE animal_id = #{animalId}
  AND user_id = #{userId}
  AND status IN ('pending', 'approved')
LIMIT 1
